class ShippingCalculator {
  calculateShippingCost(order: Order): number {
    const weight = order.getPackageWeight();
    const dims = order.getPackageDimensions();
    const dest = order.getDeliveryAddress();
    const fragile = order.getFragileFlag();
    const priority = order.getShippingPriority();

    return this.computeRate(weight, dims, dest, fragile, priority);
  }
}

class Invoice {
  private items: InvoiceItem[];
  private issuedAt: Date;

  generateTaxSummary(customer: Customer): TaxSummary {
    const region = customer.getBillingRegion();
    const exemptionId = customer.getTaxExemptionId();
    const tier = customer.getAccountTier();
    const history = customer.getPurchaseHistory();

    return TaxRules.calculate(region, exemptionId, tier, history);
  }
}

