class DiscountEngine {
  calculate(cart: ShoppingCart): number {
    const joined = cart.getOwner().getMemberSince();
    const points = cart.getOwner().getLoyaltyPoints();
    return this.applyRules(cart.getSubtotal(), joined, points);
  }
}
// Version B
class ShoppingCart {
  calculateDiscount(): number {
    const yearsAsMember = this.owner.getMemberSince();
    return this.subtotal * this.discountRate(yearsAsMember);
  }
}
